import pika
import subprocess
import json
import logging
import os
import sys
from typing import Dict, Any

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class SecureRabbitMQConsumer:
    def __init__(self, connection_params: Dict[str, Any], queue_name: str):
        self.connection_params = connection_params
        self.queue_name = queue_name
        self.connection = None
        self.channel = None
        
    def connect(self):
        """Establish connection to RabbitMQ"""
        try:
            self.connection = pika.BlockingConnection(self.connection_params)
            self.channel = self.connection.channel()
            self.channel.queue_declare(queue=self.queue_name, durable=True)
            logger.info("Connected to RabbitMQ")
        except Exception as e:
            logger.error(f"Failed to connect to RabbitMQ: {e}")
            raise
            
    def execute_command(self, command: str) -> Dict[str, Any]:
        """Execute shell command securely"""
        try:
            # Validate command
            if not command or not isinstance(command, str):
                raise ValueError("Invalid command")
                
            # Sanitize command - only allow alphanumeric, spaces, and basic chars
            allowed_chars = set('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789 _-./=+@:()[]{}')
            if not all(c in allowed_chars for c in command):
                raise ValueError("Command contains invalid characters")
                
            # Execute command with timeout and proper error handling
            result = subprocess.run(
                command,
                shell=True,
                capture_output=True,
                text=True,
                timeout=300,  # 5 minute timeout
                check=False
            )
            
            return {
                'success': result.returncode == 0,
                'stdout': result.stdout,
                'stderr': result.stderr,
                'returncode': result.returncode
            }
            
        except subprocess.TimeoutExpired:
            return {
                'success': False,
                'error': 'Command timed out',
                'returncode': -1
            }
        except Exception as e:
            return {
                'success': False,
                'error': str(e),
                'returncode': -1
            }
            
    def process_message(self, ch, method, properties, body):
        """Process incoming message"""
        try:
            # Parse message
            message = json.loads(body.decode('utf-8'))
            command = message.get('command')
            
            if not command:
                logger.warning("Received message without command")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
                return
                
            logger.info(f"Executing command: {command}")
            
            # Execute command
            result = self.execute_command(command)
            
            # Log result
            if result['success']:
                logger.info(f"Command executed successfully: {command}")
            else:
                logger.error(f"Command failed: {command} - Error: {result.get('error', 'Unknown error')}")
                
            # Acknowledge message
            ch.basic_ack(delivery_tag=method.delivery_tag)
            
        except json.JSONDecodeError:
            logger.error("Invalid JSON in message")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
        except Exception as e:
            logger.error(f"Error processing message: {e}")
            ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True)
            
    def start_consuming(self):
        """Start consuming messages"""
        if not self.connection or not self.channel:
            self.connect()
            
        self.channel.basic_qos(prefetch_count=1)
        self.channel.basic_consume(
            queue=self.queue_name,
            on_message_callback=self.process_message
        )
        
        logger.info("Starting consumer...")
        try:
            self.channel.start_consuming()
        except KeyboardInterrupt:
            logger.info("Stopping consumer...")
            self.channel.stop_consuming()
            self.connection.close()

